INSERT INTO accounts (id, name, initials, industry, industry_id, status, health, revenue, market_position, signals, pain_hierarchy, goals, target_audience, services, tactics, channels, stakeholders, strategy, last_touch) VALUES
('boa', 'Bank of America', 'BA', 'Financial Services', 'fs', 'key', 88, '$102M', 'Powers BOA execution across AML, cloud, and AI. Key account with strong infrastructure partnership. Competitive pressure from Oxford, Capgemini, Slalom.', '["Third-party risk governance tightening","Data privacy and cross-border compliance increasing","Open banking readiness","Financial crime, AML, KYC acceleration"]', '["Cost, conversion, scalability objections","Need customization vs rigid models","Enablement gaps: thought leadership, AI proof","Talent Services not landing — needs positioning","Competitor pressure: Oxford, Capgemini, Slalom"]', '["Protect/expand AML + Financial Crimes","Advance AI + Cloud position","Credibility driving sales enablement","Strengthen stakeholder access"]', '["Procurement/Vendor Management","Financial Crimes/AML leaders","Infrastructure/Cloud Leaders","AI/Data leaders","Fraud/Security stakeholders"]', '["AML program delivery","Fraud protection support","Tech delivery + infrastructure","Staff aug for cloud environments","Expansion: Crimes/AML, Cloud, AI"]', '["Web — new messaging + global","Thought Leadership — AI, AML outcomes","Brand Advocacy — Charlotte sales leaders","Local Activation — Charlotte momentum","Sales enablement — case studies into BOA assets"]', '["Email & ABM","Content & SEO","Web","Paid Media","Events & Field"]', '["Grace Han"]', '', '2026-04-05'),
('sf', 'State Farm', 'SF', 'Financial Services', 'fs', 'new-logo', 45, '$2M', 'Navigating digital transformation + catastrophic loss recovery. Net income $12.9B in 2025. New CDAO Jon Francis appointed March 2026. Deploying AI for claims triage via OpenAI. Goal: turn ATL proximity into partnership.', '["Net income $12.9B, revenue $132.3B (+7.5% YoY)","$3.1B homeowners underwriting loss (improved from $3.6B)","Jon Francis promoted to CDAO + Head of Digital","Dual digital leadership: Francis + Joe Park as EVP/CDIO","AI claims triage via OpenAI Frontier platform","Digital knowledge assistant for contact centers"]', '["AI/ML talent for claims automation — competing nationally","Data/analytics hiring surge under new CDAO mandate","Digital product/UX engineers for platform modernization","Transformation speed vs homeowners loss management","Property insurance cat-risk and climate modeling talent gap"]', '["Turn ATL proximity into partnership","Reposition from OSP vendor to trusted delivery partner","Earn CSP eligibility (Tech + Non-Tech)","$2M 2026 revenue goal","Measurable CSP milestone progress"]', '["Procurement: Vendor Mgmt, Directors, Category Leads","Claims/Underwriting: Directors/VP, Ops Managers","Data + Tech: Head of Data, AI/Automation Leaders"]', '["Cost Optimization — reduce spend without risk","Rapid Response — surge support for operations","Tech Scale — data delivery + AI-ready foundations"]', '["Web — Insurance page with OSP/CSP language","Social/PR — organic through IG SMEs, local PR","Brand Advocacy — LinkedIn credibility coaching","TL Ads — targeted to top-of-funnel","Local Activation — ATL IG experience sessions","IP-based customization for SF contacts","Proof pack: case snapshots + metrics"]', '["Paid Media","Email & ABM","Web","Organic Social","Events & Field","Content & SEO"]', '["Charlie Loveall","Rachel Peacock"]', 'Two-track: Track A (Deepen Tech) + Track B (Break Non-Tech). CSP eligibility within 6-9 months.', '2026-04-01'),
('c1', 'Capital One', 'C1', 'Financial Services', 'fs', 're-entry', 30, 'TBD', 'Re-entering after long non-engagement. Post-Discover merger reduced vendor list. Fraud risk driving vendor scrutiny. Must rebuild trust from vendor risk to fraud-aware partner.', '["Procurement trust is the barrier","Fraud risk driving vendor scrutiny","Post-Discover merger raised vendor bar","AML/KYC regulatory pressure increasing","Third-party risk governance tightening"]', '["Fraud + false candidate exposure","AML/KYC throughput + regulatory pressure","Procurement trust + vendor consolidation","Rebuilding from vendor risk perception","Limited access beyond MSP layer"]', '["Re-enter vendor ecosystem — earn one safe yes","Rebuild procurement/ESM trust","Reposition as fraud-aware partner","Win low-risk first engagement","Expand based on performance, not persuasion"]', '["Fraud Risk/Security/Talent Risk Leaders","AML/KYC Program Owners, Transaction Monitoring","Procurement Category Leaders, ESM Leadership VP+"]', '["Fraud/Risk Protection — fraud-first screening","AML/KYC Solutions — compliant delivery","Procurement Re-Entry — controlled low-risk approach"]', '["Web — C1 landing page + proof hub","Paid Social — organic through IG SMEs","Email — FS tailored to known C1 contacts","Brand Advocacy — risk-first delivery posts","Targeted Outreach — procurement + AML/KYC leaders","Events — small local touchpoint for trust"]', '["Paid Media","Email & ABM","Web","Content & SEO","Events & Field"]', '["Grace Han"]', 'Lead with protection → Earn low-risk win → Convert proof into expansion', '2026-03-15'),
('jnj', 'Johnson & Johnson', 'JJ', 'Life Sciences', 'ls', 'key', 90, '$104M', 'Accelerate innovation across R&D, manufacturing, supply chain. Proven long-term partnership. Strong custom teams and managed service delivery. Shifting from building facilities to operationalizing them.', '["Shift to operationalizing equipment, tech, workforce","New US facility builds with major investment","AI enablement in manufacturing/operations","Continued specialized scientific talent need","LATAM global delivery expansion"]', '["Limited brand recognition in enterprise procurement","Vendor selection influenced by analyst platforms","Perceived gap in R+D and manufacturing expertise","Difficulty demonstrating credibility in technical LS","Competitive pressure from specialized consultants","Lost opportunities from executive consulting questions"]', '["Protect & expand existing delivery","Strengthen executive/procurement engagement","Position as services partner beyond staffing","Grow services across R&D, manufacturing, supply chain"]', '["Procurement/Vendor Management","Manufacturing/Operations Senior Leaders","R+D/Scientific program leadership","Supply chain/Commercialization stakeholders","Digital innovation leaders (AI + data)"]', '["FSP custom teams","LS technical staffing + consulting","Manufacturing ops + facility staffing","QA/QC + technical documentation","Data engineering + enablement","Scientific insourcing + R+D expertise","Tech transfer + commercialization","Facility stand-up + operational readiness"]', '["Content — Speed to Commercialization, GxP, Tech Transfer, AI","Brand Advocacy — consistent LS talk track","Sales Enablement — proof packs by service line","Priority Account Plays — geo-targeted + account narrative","Web — updated J+J pages with proof + CTAs"]', '["Content & SEO","Web","Paid Media","Email & ABM","Events & Field","Organic Social"]', '["Charlie Loveall","Bretlyn Morales","Chandan Barhate"]', '', '2026-04-06'),
('lilly', 'Eli Lilly', 'EL', 'Life Sciences', 'ls', 'growth', 55, 'TBD', 'Rapid GLP-1 scale-up driving M&Q demand. 80% of investment in Manufacturing & Quality. Investing heavily in AI process optimization. Saturated with vendors — needs strategic FSP partners.', '["Rapid M&Q scale-up: oral GLP-1 + future pipeline","Accelerating digital transformation + AI/data","Cost, quality, compliance pressure while scaling","New facilities: Lebanon IN, Virginia, Houston, Cork Ireland","80% of investment in Manufacturing & Quality"]', '["Rapid M&Q Scale Up — compliant workforce fast","Digital/AI Acceleration — AI-driven optimization","Cost/Compliance Pressure vs Accenture/Deloitte","Limited IG visibility beyond staffing","Not yet positioned as trusted FSP leader"]', '["Increase brand awareness + relationship depth","Position as trusted FSP (not just staffing)","Increased meetings with decision makers","Recognition as trusted FSP partner"]', '["M&Q: VP Manufacturing, Director Engineering, QA","AI/Digital: Heads of Data, AI Digital Labs","Procurement: Procurement & Category Leaders"]', '["M&Q — stand up, train, manage compliant workforce","AI/Data/Digital — build + integrate compliant AI/ML","FSP Model — customizable, scalable delivery","Engineering teams + documentation","Validation (CQV/CSV)"]', '["Web — LS page anchored in FSP model","Social/PR — organic through LS SMEs, Chandan PR","Personal Branding — sessions for Lilly sales leaders","TL Ads — targeted to top-of-funnel","IP-based customization for Lilly contacts","Email — LS tailored to known Lilly contacts","Retargeting — highlight partnership wins"]', '["Content & SEO","Web","Paid Media","Email & ABM","Organic Social","Events & Field"]', '["Charlie Loveall","Bretlyn Morales","Chandan Barhate","Bri Sundstrom"]', 'Showcase J&J/Merck delivery success, position as equally capable FSP.', '2026-04-02');
